var SD={agenda:"Cross-patient, cross-doctor command center showing today's Dandy-related appointments, pending tasks, and AI alerts. Surfaces what matters most for the practice right now, with quick-action buttons for starting scans, opening cases, and joining lab reviews.",alerts:"Real-time notification center fed by AI Scan Review, lab production updates, shipment tracking, and scheduling conflicts. Alerts prioritized by clinical severity - critical prep issues surface above informational updates.",schedule:"Full-day timeline view with Dandy case context, operatory room assignments, and estimated durations. Visual indicators distinguish scan appointments, seating appointments, and design review sessions.",tasks:"Actionable task queue for the practice team - pending scans, cases needing review, follow-ups, and lab communication items. Each task links directly to its parent case for one-click context.",scan:"Live Vision scanner interface with real-time scan progress visualization, coverage heat map, and AI-powered guidance overlay. Checklist tracks required captures: buccal, occlusal, lingual, contacts, opposing, and bite registration.",review:"AI Scan Review results dashboard showing overall prep quality score with breakdown by coverage, margins, clearance, and prep quality. Visual overlays highlight detected issues with severity ratings and recommended actions.",patient:"Simplified, patient-facing view designed for chairside explanation. Uses plain language and clear visuals to explain findings, treatment plan, and next steps. Optimized for iPad display during consultations.",submit:"Pre-flight submission workflow validating scan quality, prescription completeness, shade selection, photo requirements, and AI review status. Cases cannot submit until all required gates pass.",active:"Filterable case list across the entire practice. Filter by doctor, product type, status, priority, and journey type. Each row links to the full case workspace with timeline and communication history.",journeys:"Multi-appointment journey tracker for Smile Makeovers (3 appointments), Dentures (2 appointments), and Implant cases. Visual progress bars show milestone completion with estimated dates.",archive:"Historical case archive with full search, date filtering, and quality audit capabilities. Supports export for practice analytics and insurance documentation.",newcase:"New case creation wizard with journey template selection. AI pre-populates fields from existing patient scan data. Supports all product types: crowns, bridges, veneers, dentures, implants, guards, and appliances.",reviews:"Scheduled and completed Live Design Review sessions with Dandy lab technicians. Includes video call scheduling, 3D model annotation tools, and session recording for reference.",viewer:"Interactive 3D viewer for wax-ups, designs, and final restorations. Supports rotation, zoom, measurement tools, and comment pinning. Side-by-side comparison mode for before/after.",approvals:"Design approval workflow with side-by-side comparison views, change request forms, and decision logging for audit trails. Supports conditional approvals with modification notes.",gallery:"Clinical photo gallery organized by case and patient. Supports before/after comparison layouts, shade matching documentation, and tagged photo categorization.",tracking:"Real-time lab case tracking showing current production stage, estimated completion, and priority level. Supports both list and kanban views with drag metaphor for stage transitions.",production:"Kanban-style production pipeline visualization showing cases flowing through Design → Milling → Staining/Glazing → QC → Shipping stages. Each card shows patient, product, and ETA.",shipping:"Shipment tracking dashboard with carrier integration (FedEx Priority), tracking numbers, delivery estimates, and arrival notifications. Historical shipment log for reference.",remakes:"Remake tracking with root-cause analysis - categorized by scan issues, prep problems, lab errors, and fit issues. Feeds into quality improvement workflows and training recommendations.",quality:"Quality analytics dashboard showing remake rates over time, segmented by doctor, product type, and root cause. First-pass success rate and AI Scan Review effectiveness metrics.",turnaround:"Turnaround time analysis from scan submission to final seating, segmented by workflow type (crowns, dentures, smile makeovers). Identifies bottlenecks and tracks improvement trends.",aiperf:"AI Scan Review performance metrics - detection accuracy rate, false positive percentage, cases where AI feedback prevented remakes, and scan score distribution across all doctors.",teamperf:"Team performance dashboard showing case volume, quality metrics, active case load, and remake percentages per practice member. Supports performance reviews and training planning.",users:"Practice team management with role-based access control. Supports multi-location practices with per-location permissions and activity logging.",settings:"System configuration for notification preferences, default workflows, shade guide selection, material preferences, and communication channel settings.",equipment:"Connected equipment management for Vision scanners and operatory displays. Firmware version tracking, calibration scheduling, usage metrics, and maintenance alerts.",labs:"Lab partner configuration with default material preferences, turnaround agreements, communication preferences, and contact information. Supports multiple lab relationships."};
var SEC_DESC={"Today":"The practice's daily command center - appointments, alerts, tasks, and schedule unified for all Dandy-related clinical activity across doctors and operatories.","Chairside":"Operatory-centric tools for the clinical moment - live scanning with AI guidance, real-time prep quality analysis, patient-facing explanations, and validated case submission.","Cases":"Full case lifecycle management - from initial scan through lab production to final seating, including multi-appointment journey tracking for complex workflows.","Design":"Collaborative design workspace connecting practice and lab - Live Design Reviews with 3D visualization, approval workflows, and clinical photography management.","Lab":"Production visibility and logistics - real-time tracking through Dandy's lab pipeline, shipment management, and remake analysis for continuous quality improvement.","Analytics":"Data-driven practice optimization - quality metrics, turnaround analysis, AI performance tracking, and team dashboards that connect design decisions to clinical outcomes.","Admin":"Practice configuration and management - team roles, connected equipment, lab partnerships, and system preferences that support multi-location operations."};
