var ujSteps=[{id:"scan",title:"Chairside Scan",role:"Dental Assistant",desc:"Assistant opens Vision scanner, selects patient and tooth. AI guidance overlay shows optimal scan path. Real-time coverage percentage and quality indicators update as the scan progresses through buccal, occlusal, lingual surfaces."},{id:"review",title:"AI Prep Analysis",role:"System / AI",desc:"AI Scan Review automatically evaluates the preparation quality. Checks for undercuts (>3° flagged), margin clarity (tissue retraction adequacy), occlusal clearance (material-specific thresholds), and overall prep geometry. Issues displayed with severity ratings and visual overlays on the 3D scan."},{id:"decide",title:"Clinical Decision",role:"Dentist",desc:"Dentist reviews AI findings with the patient. Can accept and proceed to submission, re-prep the tooth and re-scan, or override the AI recommendation with clinical justification. Patient-facing view available for chairside explanation using plain language."},{id:"submit",title:"Case Submission",role:"Dentist / System",desc:"Pre-flight checklist validates: scan quality score, margin capture, bite registration, shade selection, AI review pass, and clinical photos. All gates must pass before the case can be submitted to Dandy lab with complete prescription and assets."},{id:"track",title:"Lab & Delivery",role:"Lab / Practice",desc:"Case tracked through Dandy's production pipeline: Design → Milling → Finishing → QC → Shipping. Live Design Review available for complex cases. Practice receives milestone notifications and delivery tracking. Final seating appointment auto-scheduled."}];
var ujSteps2=[{id:"consult",title:"Consultation",role:"Dentist / Patient",desc:"Initial consultation with DSD (Digital Smile Design) analysis. Photos, impressions, and patient goals documented. AI suggests optimal veneer shapes based on facial analysis and tooth proportions."},{id:"design",title:"Smile Design",role:"Lab Tech / Dentist",desc:"Lab creates digital smile design with 4+ veneer options. Live Design Review session to refine shape, shade, and proportions. Dentist and patient approve the digital mockup together."},{id:"trial",title:"Test Drive",role:"Dentist / Patient",desc:"Temporary veneers (provisionals) fabricated from the approved design. Patient wears them for 1-2 weeks to evaluate aesthetics, function, and comfort. Feedback captured digitally."},{id:"prep",title:"Final Preparation",role:"Dentist",desc:"Based on test drive feedback, minimal tooth preparation performed. Final impressions with Vision scanner. AI validates prep quality and margin clarity for all involved teeth simultaneously."},{id:"seat",title:"Final Seating",role:"Dentist",desc:"Lab-fabricated veneers arrive. Dentist verifies fit, shade match, and contacts. Before/after photos documented. Patient approves final result. Case marked complete."}];
var ujSteps3=[{id:"scanD",title:"Scan & Registration",role:"Dentist / Assistant",desc:"Full-arch digital scan with Vision scanner. Bite registration captured. Facebow measurements recorded digitally. AI analyzes arch form and vertical dimension for design parameters."},{id:"designD",title:"Digital Design",role:"Lab Tech",desc:"Lab creates digital denture design using scan data. Tooth selection, arrangement, and gingival contouring completed in CAD software. Design Review session with dentist for approval."},{id:"tryIn",title:"Try-In Appointment",role:"Dentist / Patient",desc:"3D-printed try-in denture evaluated for fit, esthetics, and phonetics. Patient feedback on tooth shade, position, and lip support captured. Modifications noted for final fabrication."},{id:"final",title:"Final Delivery",role:"Dentist",desc:"Final processed denture delivered. Fit verified with pressure-indicating paste. Occlusal adjustments made chairside. Patient educated on care and maintenance. Follow-up scheduled."}];
var ujSteps4=[{id:"cbct",title:"CBCT & Planning",role:"Dentist",desc:"CBCT scan acquired and uploaded to implant planning software. Virtual implant placed with consideration for bone density, nerve proximity, and prosthetic position. Surgical guide designed digitally."},{id:"surgery",title:"Implant Placement",role:"Surgeon / Dentist",desc:"Guided implant surgery performed using 3D-printed surgical guide. Implant placed at planned depth and angle. Healing abutment attached. Post-op radiograph confirms position."},{id:"heal",title:"Osseointegration",role:"System / Dentist",desc:"3-4 month healing period monitored through scheduled check-ins. EnamelOS tracks healing milestones and reminds the practice when the patient is due for impression appointment."},{id:"scanI",title:"Impression & Design",role:"Dentist / Lab",desc:"Scan body placed on implant. Digital impression captured with Vision scanner. Lab designs custom abutment and crown. Live Design Review to verify emergence profile and contours."},{id:"seatI",title:"Final Restoration",role:"Dentist",desc:"Custom abutment torqued to specification. Implant crown seated and occlusion verified. Before/after photos documented. Patient receives care instructions for long-term maintenance."}];
var ujSteps5=[{id:"scanG",title:"Digital Scan",role:"Dental Assistant",desc:"Full-arch digital scan captured with Vision scanner. AI verifies scan completeness for guard fabrication. Bite registration in maximum intercuspation recorded for occlusal analysis."},{id:"designG",title:"Guard Design",role:"Lab Tech",desc:"Lab designs occlusal splint using scan data. Thickness, retention, and occlusal scheme determined based on bruxism severity. Design Review available for complex cases."},{id:"fabG",title:"Fabrication",role:"Lab",desc:"Guard manufactured using thermoforming or milling based on prescribed material (hard, soft, or dual-laminate). QC checks for fit accuracy and surface finish before shipping."},{id:"fitG",title:"Fitting & Adjustment",role:"Dentist",desc:"Guard delivered to patient. Fit verified and occlusal contacts adjusted chairside. Patient educated on wear schedule, cleaning protocol, and when to return for evaluation."}];

